}

fn get_table(&mut self, idx: i32) -> Result<LuaType, LuaError> {
    lua_vm::api::get_table(self, idx)
}

fn get_stack(&mut self, level: i32, ar: &mut LuaDebug) -> bool {
    let mut lvm_ar = lua_vm::debug::LuaDebug::default();
