    // In Rust: find by pointer identity (Rc::ptr_eq) and remove.
    // PERF(port): O(n) retain vs O(1) intrusive unlink — profile in Phase B.
    state.openupval.retain(|candidate| !GcRef::ptr_eq(candidate, uv));
